1	const NEIGHBOR_OFFSETS: Array<[number, number]> = [
2	  [-1, -1], [-1, 0], [-1, 1],
3	  [0, -1],           [0, 1],
4	  [1, -1],  [1, 0],  [1, 1]
5	];
6	
7	export function nextGeneration(grid: Array<[number, number]>): Array<[number, number]> {
8	  // Create a set for O(1) cell lookup instead of O(N) array search
9	  const gridSet = new Set(grid.map(([x, y]) => `${x},${y}`));
10	
11	  // Helper to check if a cell exists at coordinates
12	  const cellExists = (x: number, y: number): boolean => {
13	    return gridSet.has(`${x},${y}`);
14	  };
15	
16	  // Count neighbors for each cell
17	  const countNeighbors = (x: number, y: number): number => {
18	    return NEIGHBOR_OFFSETS.filter(([dx, dy]) => cellExists(x + dx, y + dy)).length;
19	  };
20	
21	  // Rule 1 & 3: Live cells survive with 2-3 neighbors
22	  const survivingCells = grid.filter(([x, y]) => {
23	    const neighbors = countNeighbors(x, y);
24	    return neighbors >= 2 && neighbors <= 3;
25	  });
26	
27	  // Rule 4: Dead cells with exactly 3 neighbors become alive
28	  const deadCellsSet = new Set<string>();
29	  // Find all dead cells adjacent to live cells
30	  for (const [x, y] of grid) {
31	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
32	      const nx = x + dx;
33	      const ny = y + dy;
34	      if (!cellExists(nx, ny)) {
35	        deadCellsSet.add(`${nx},${ny}`);
36	      }
37	    }
38	  }
39	
40	  // Create new cells from dead cells with exactly 3 neighbors
41	  const newCells: Array<[number, number]> = [];
42	  for (const cell of deadCellsSet) {
43	    const [x, y] = cell.split(',').map(Number) as [number, number];
44	    if (countNeighbors(x, y) === 3) {
45	      newCells.push([x, y]);
46	    }
47	  }
48	
49	  // Combine surviving cells and new cells
50	  const result = [...survivingCells, ...newCells];
51	  return result;
52	}
53	

