```
function nextGeneration(grid: Array<[number, number]>): Array<[number, number]> {
  // gridSet creation
  const gridSet = new Set(grid.map(([x, y]) => `${x},${y}`));

  const cellExists = (x: number, y: number): boolean => {
    return gridSet.has(`${x},${y}`);
  };

  const countNeighbors = (x: number, y: number): number => {
    return NEIGHBOR_OFFSETS.filter(([dx, dy]) => cellExists(x + dx, y + dy)).length;
  };

  const survivingCells = grid.filter(([x, y]) => {
    const neighbors = countNeighbors(x, y);
    return neighbors >= 2 && neighbors <= 3;
  });

  const deadCellsSet = new Set<string>();
  for (const [x, y] of grid) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      if (!cellExists(nx, ny)) {
        deadCellsSet.add(`${nx},${ny}`);
      }
    }
  }

  const newCells: Array<[number, number]> = [];
  for (const cell of deadCellsSet) {
    const [x, y] = cell.split(',').map(Number) as [number, number];
    if (countNeighbors(x, y) === 3) {
      newCells.push([x, y]);
    }
  }

  const result = [...survivingCells, ...newCells];
  return result;
}
```

